const settings = $input.first().json;

// Current time in IST (UTC+5:30)
const now = new Date();
const istOffset = 5.5 * 60 * 60 * 1000;
const ist = new Date(now.getTime() + istOffset);
const currentHour = ist.getUTCHours();
const currentMin  = ist.getUTCMinutes();
const currentTime = `${String(currentHour).padStart(2,'0')}:${String(currentMin).padStart(2,'0')}`;

// Offset — how many minutes before prayer to call
const offset = settings.offset_minutes || 15;

// Check each prayer
const prayers = [
  { key: 'fajr',    name: 'Fajr',    time: settings.fajr },
  { key: 'dhuhr',   name: 'Dhuhr',   time: settings.dhuhr },
  { key: 'asr',     name: 'Asr',     time: settings.asr },
  { key: 'maghrib', name: 'Maghrib', time: settings.maghrib },
  { key: 'isha',    name: 'Isha',    time: settings.isha },
];

let triggerPrayer = null;

for (const prayer of prayers) {
  if (!prayer.time) continue;
  const [pH, pM] = prayer.time.split(':').map(Number);
  // Subtract offset minutes
  let callH = pH;
  let callM = pM - offset;
  if (callM < 0) { callH -= 1; callM += 60; }
  const callTime = `${String(callH).padStart(2,'0')}:${String(callM).padStart(2,'0')}`;
  if (callTime === currentTime) {
    triggerPrayer = prayer;
    break;
  }
}

if (!triggerPrayer) {
  // No prayer to trigger right now — stop workflow
  return [];
}

console.log(`🕌 Triggering calls for ${triggerPrayer.name} — call time: ${currentTime}`);

return [{ json: { prayer: triggerPrayer, currentTime } }];

