const contacts = $input.all();

let prayerName = 'Fajr';
let prayerKey  = 'fajr';

try {
  const p = $('Check If Prayer Time Now').first().json.prayer;
  if (p) { prayerName = p.name; prayerKey = p.key; }
} catch(e) {
  console.log('Testing mode — using Fajr');
}

const relevant = contacts.filter(item => {
  const c = item.json;
  const prayers = Array.isArray(c.prayers) ? c.prayers : JSON.parse(c.prayers || '[]');
  return prayers.some(p => p.toLowerCase() === prayerName.toLowerCase());
});

console.log(`📞 ${relevant.length} contacts to call for ${prayerName}`);

if (!relevant.length) return [];

return relevant.map(item => ({
  json: {
    ...item.json,
    prayerName,
    prayerKey
  }
}));

const contact = $input.first().json;
const name       = contact.name       || 'Brother';
const prayerName = contact.prayerName || 'Fajr';
const offset     = 15;

// Exotel needs 0XXXXXXXXXX format not +91
const phone = (contact.phone || '').replace('+91', '0');

const message = `Assalamu Alaikum ${name}. This is your Salah reminder. ${prayerName} prayer time is in ${offset} minutes. Please prepare for salah. JazakAllah Khair.`;

return [{ json: { ...contact, message, name, prayerName, phone } }];
